// Normalize Google Sheets data for Cloudflare D1 database
// Extract row data and determine operation type (insert/update)

const input = $input.first().json;
const sheetName = input.sheetName || 'Sheet1';
const spreadsheetId = input.spreadsheetId;

// Extract row data based on trigger type
let rowData = {};
let operation = 'unknown';
let rowId = null;

if (input.eventType === 'rowUpdated') {
  // Row updated event
  operation = 'update';
  rowData = input.newRow || input.changes || {};
  rowId = input.rowId || input.rowIndex;
} else if (input.eventType === 'newRow') {
  // New row event
  operation = 'insert';
  rowData = input.row || input.changes || {};
  rowId = input.rowId || input.rowIndex;
} else {
  // Fallback for other event types
  rowData = input.changes || input.row || {};
  operation = 'insert';
  rowId = input.rowId || input.rowIndex;
}

// Build Cloudflare D1 compatible data structure
const d1Data = {
  operation: operation,
  spreadsheet_id: spreadsheetId,
  sheet_name: sheetName,
  row_id: rowId,
  timestamp: new Date().toISOString(),
  // Extract column data (assuming common menu columns)
  data: {
    name: rowData.name || rowData.Name || rowData['Menu Item'] || '',
    description: rowData.description || rowData.Description || '',
    price: parseFloat(rowData.price || rowData.Price || rowData.Cost || 0) || 0,
    category: rowData.category || rowData.Category || 'uncategorized',
    available: Boolean(rowData.available !== undefined ? rowData.available : (rowData.Available !== undefined ? rowData.Available : true)),
    // Include all other columns dynamically
    ...Object.fromEntries(
      Object.entries(rowData).filter(([key]) => 
        !['name', 'Name', 'Menu Item', 'description', 'Description', 'price', 'Price', 'Cost', 'category', 'Category', 'available', 'Available'].includes(key)
      )
    )
  },
  raw_data: JSON.stringify(rowData)
};

return [{ json: d1Data }];
